DROP TABLE IF EXISTS `oner_verimlilikler`;

CREATE TABLE `oner_verimlilikler` (
  `id` INT AUTO_INCREMENT PRIMARY KEY,
  `yil` DATETIME,
  `cig_sut_verimi_lt` DOUBLE,
  `buyukbas_karkas_et_verimi_kg` DOUBLE,
  `kucukbas_karkas_et_verimi_kg` DOUBLE,
  `bal_verimi_kg` DOUBLE,
  `created_at` TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

